{
var seed = GetInt(parameters, "seed", context.Seed);
var time = GetFloat(parameters, "time", 0f);
var smokeType = GetChoice(parameters, "smokeType", "thick");
var size2 = GetFloat(parameters, "size", 0.5f);
var density = GetFloat(parameters, "density", 0.6f);
var speed = GetFloat(parameters, "speed", 0.5f);
var wind = GetFloat(parameters, "wind", 0f);
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 1));
var smokeColor = GetColor(parameters, "smokeColor", System.Windows.Media.Color.FromRgb(160, 150, 140));

var cR = smokeColor.R/255f; var cG = smokeColor.G/255f; var cB = smokeColor.B/255f;
var size = context.TileSize;
var result = new PixelBuffer(size, size);

var riseRate = 1f; var expandRate = 1f; var turbulenceStr = 1f;
switch (smokeType)
{
    case "mist": riseRate = 0.4f; expandRate = 1.5f; turbulenceStr = 0.5f; break;
    case "steam": riseRate = 1.5f; expandRate = 0.8f; turbulenceStr = 0.8f; break;
    case "dust": riseRate = 0.3f; expandRate = 0.6f; turbulenceStr = 2f; break;
    default: riseRate = 0.8f; expandRate = 1f; turbulenceStr = 1f; break;
}

var scale = size2 * 3f;
var period = Math.Max(1, (int)(size * scale * 0.3f));

var timeOffX = time * speed * wind * 2f;
var timeOffY = time * speed * riseRate * (-1.5f);
var windOff = wind * 0.3f;

result.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size * scale + timeOffX + windOff;
    var v = y / (float)size * scale + timeOffY;

    var n1 = TileableFractalNoise(u, v, period, 5, 0.5f, 2.1f, seed);
    var n2 = TileableFractalNoise(u * 1.7f + 20f, v * 1.7f + 20f, period, 3, 0.6f, 2.3f, seed + 500);

    var tu = u + (n2 - 0.5f) * turbulenceStr * 0.2f;
    var tv = v + (n1 - 0.5f) * turbulenceStr * 0.2f;
    var n = TileableFractalNoise(tu, tv, period, 4, 0.55f, 2.2f, seed + 200);

    var yFrac = y / (float)size;
    var riseCenter = 1f - size2 * 0.5f;
    var riseMask = MathF.Exp(-MathF.Abs(yFrac - riseCenter) * 3f / Math.Max(0.1f, size2));

    var xCenter = 0.5f + wind * 0.1f;
    var xDist = MathF.Abs(x / (float)size - xCenter);
    var spreadMask = MathF.Exp(-xDist * xDist * 8f / (size2 * size2 + 0.01f));

    var alpha = Math.Clamp(n * density * riseMask * spreadMask, 0f, 1f);
    result.SetPixel(x, y, cR, cG, cB, alpha);
});
return result;
}
